    "title": "Asynchronous Apex",
    "permalink": "http://localhost:1313/sf-ohana/apex/asynchronous/",
    "summary": "Asynchronous Apex Asynchronous Apex allows you to run processes in the background, enabling more flexible and efficient processing of large data volumes.\nTypes of Asynchronous Apex 1. Future Methods Future methods run in the background and are useful for callouts and operations that don\u0026rsquo;t require immediate processing.\npublic class AccountProcessor { @future public static void updateAccountsAsync(Set\u0026lt;Id\u0026gt; accountIds) { List\u0026lt;Account\u0026gt; accounts = [SELECT Id, Name FROM Account WHERE Id IN :accountIds]; // Process accounts update accounts; } @future(callout=true) public static void makeCallout(String endpoint) { Http http = new Http(); HttpRequest request = new HttpRequest(); request.",
    "content": "Asynchronous Apex Asynchronous Apex allows you to run processes in the background, enabling more flexible and efficient processing of large data volumes.\nTypes of Asynchronous Apex 1. Future Methods Future methods run in the background and are useful for callouts and operations that don\u0026rsquo;t require immediate processing.\npublic class AccountProcessor { @future public static void updateAccountsAsync(Set\u0026lt;Id\u0026gt; accountIds) { List\u0026lt;Account\u0026gt; accounts = [SELECT Id, Name FROM Account WHERE Id IN :accountIds]; // Process accounts update accounts; } @future(callout=true) public static void makeCallout(String endpoint) { Http http = new Http(); HttpRequest request = new HttpRequest(); request.setEndpoint(endpoint); request.setMethod(\u0026#39;GET\u0026#39;); HttpResponse response = http.send(request); // Process response } } 2. Batch Apex Batch Apex is ideal for processing large data sets that would exceed normal processing limits.\npublic class AccountBatch implements Database.Batchable\u0026lt;sObject\u0026gt;, Database.Stateful { private Integer recordsProcessed = 0; public Database.QueryLocator start(Database.BatchableContext bc) { return Database.getQueryLocator([ SELECT Id, Name, AnnualRevenue FROM Account WHERE CreatedDate = LAST_N_DAYS:30 ]); } public void execute(Database.BatchableContext bc, List\u0026lt;Account\u0026gt; scope) { for (Account acc : scope) { // Process each account acc.Description = \u0026#39;Processed on \u0026#39; + Date.today(); recordsProcessed++; } update scope; } public void finish(Database.BatchableContext bc) { System.debug(\u0026#39;Batch completed. Records processed: \u0026#39; + recordsProcessed); // Send email notification AsyncApexJob job = [SELECT Id, Status, CompletedDate FROM AsyncApexJob WHERE Id = :bc.getJobId()]; // Email logic } } // Execute batch AccountBatch batch = new AccountBatch(); Database.executeBatch(batch, 200); 3. Queueable Apex Queueable Apex provides more flexibility than future methods with the ability to chain jobs.\npublic class AccountQueueable implements Queueable { private List\u0026lt;Account\u0026gt; accounts; public AccountQueueable(List\u0026lt;Account\u0026gt; accounts) { this.accounts = accounts; } public void execute(QueueableContext context) { // Process accounts for (Account acc : accounts) { acc.Description = \u0026#39;Processed by Queueable\u0026#39;; } update accounts; // Chain another job if needed if (!Test.isRunningTest()) { System.enqueueJob(new ContactQueueable()); } } } // Enqueue the job System.enqueueJob(new AccountQueueable(accountList)); 4. Scheduled Apex Scheduled Apex allows you to schedule code execution at specific times.\npublic class AccountScheduler implements Schedulable { public void execute(SchedulableContext sc) { // Execute batch or other logic Database.executeBatch(new AccountBatch(), 200); } } // Schedule the job String cronExp = \u0026#39;0 0 12 * * ?\u0026#39;; // Daily at noon System.schedule(\u0026#39;Daily Account Processing\u0026#39;, cronExp, new AccountScheduler()); Comparison Table Feature Future Batch Queueable Scheduled Governor Limits Higher Highest Higher Normal Can call from Trigger Yes No Yes No Supports Callouts Yes Yes Yes Yes Can chain jobs No Yes Yes Yes Can use non-primitive types No Yes Yes Yes Can track job progress No Yes Yes Yes Best Practices 1. Choose the Right Tool Future Methods: Simple fire-and-forget operations Batch Apex: Large data volume processing Queueable: Complex logic with chaining needs Scheduled: Time-based execution requirements 2. Error Handling public class RobustBatch implements Database.Batchable\u0026lt;sObject\u0026gt;, Database.RaisesPlatformEvents { public void execute(Database.BatchableContext bc, List\u0026lt;Account\u0026gt; scope) { List\u0026lt;Database.SaveResult\u0026gt; results = Database.update(scope, false); for (Integer i = 0; i \u0026lt; results.size(); i++) { if (!results[i].isSuccess()) { // Log errors for (Database.Error err : results[i].getErrors()) { System.debug(\u0026#39;Error: \u0026#39; + err.getMessage()); } } } } } 3. Testing Asynchronous Apex @isTest private class AsynchronousApexTest { @isTest static void testFutureMethod() { // Create test data Set\u0026lt;Id\u0026gt; accountIds = new Set\u0026lt;Id\u0026gt;(); // Add account IDs Test.startTest(); AccountProcessor.updateAccountsAsync(accountIds); Test.stopTest(); // Assertions - code runs synchronously in test context // Verify results } @isTest static void testBatchApex() { // Create test data List\u0026lt;Account\u0026gt; accounts = TestDataFactory.createAccounts(200); Test.startTest(); Database.executeBatch(new AccountBatch(), 200); Test.stopTest(); // Verify batch results } } Governor Limits Comparison Limit Type Synchronous Future Batch (per batch) Queueable SOQL queries 100 200 200 200 DML rows 10,000 10,000 10,000 10,000 Heap size 6 MB 12 MB 12 MB 12 MB CPU time 10,000 ms 60,000 ms 60,000 ms 60,000 ms Common Patterns Retry Logic public class RetryableQueueable implements Queueable { private Integer retryCount; private static final Integer MAX_RETRIES = 3; public RetryableQueueable(Integer retryCount) { this.retryCount = retryCount; } public void execute(QueueableContext context) { try { // Main logic } catch (Exception e) { if (retryCount \u0026lt; MAX_RETRIES) { System.enqueueJob(new RetryableQueueable(retryCount + 1)); } else { // Log final failure } } } } Chaining Pattern public class ChainedQueueable implements Queueable, Database.AllowsCallouts { private String stage; public ChainedQueueable(String stage) { this.stage = stage; } public void execute(QueueableContext context) { switch on stage { when \u0026#39;STAGE_1\u0026#39; { // Process stage 1 System.enqueueJob(new ChainedQueueable(\u0026#39;STAGE_2\u0026#39;)); } when \u0026#39;STAGE_2\u0026#39; { // Process stage 2 System.enqueueJob(new ChainedQueueable(\u0026#39;STAGE_3\u0026#39;)); } when \u0026#39;STAGE_3\u0026#39; { // Final processing } } } } ",
